\centering
\begin{tikzpicture}[scale=1, every node/.style={circle, draw, minimum size=0.7cm}]
% First graph: path on 4 vertices
\node[draw=none, anchor=west] (forb1) at (-4,0) {$\alpha_1 \neq \alpha_2$};
\node (u1) at (0,0) {$u_1$};
